package com.venom.ui.components.dialogs

import android.util.Log
import android.webkit.WebView

/**
 * Process-wide helper to probe WebView provider initialization.
 * Call ensureInitialized(context) from the main thread to try a single initialization.
 */
object WebViewInit {
    @Volatile
    var attempted: Boolean = false
        private set

    @Volatile
    var success: Boolean = false
        private set

    /**
     * Attempts to create and immediately destroy a WebView to force provider init.
     * Must be called on the main thread.
     * Returns true if provider initialization succeeded.
     */
    fun ensureInitialized(context: android.content.Context): Boolean {
        synchronized(this) {
            if (attempted) return success
            attempted = true
            try {
                val w = WebView(context)
                // destroy immediately to avoid leaking resources
                w.destroy()
                success = true
            } catch (t: Throwable) {
                Log.e("WebViewInit", "WebView provider initialization failed", t)
                success = false
            }
            return success
        }
    }
}
